// ════════════════════════════════════════════════════════
// TOOL: BUSCAR PROFISSIONAIS POR SERVIÇO
// Lista funcionários habilitados para um serviço
// ════════════════════════════════════════════════════════

const input = $input.item.json;
const query = input.query || '';
const organizacaoId = input.organizacao_id || input.organizacaoId;
let servicoId = input.servico_id || input.servicoId;

// Tentar extrair servico_id do query
if (!servicoId && query) {
  const match = query.match(/(\d+)/);
  if (match) servicoId = match[1];
}

if (!servicoId) {
  return [{ json: { error: true, message: 'servico_id não informado. Primeiro selecione um serviço.' } }];
}
if (!organizacaoId) {
  return [{ json: { error: true, message: 'organizacao_id não informado.' } }];
}

return [{ json: { servico_id: servicoId, organizacao_id: organizacaoId } }];

// Formatar lista de profissionais
const items = $input.all();
const profissionais = items
  .map(item => item.json)
  .filter(item => item.funcionario_id);

if (profissionais.length === 0) {
  return [{
    json: {
      response: JSON.stringify({
        profissionais: [],
        mensagem: 'Nenhum profissional disponível para este serviço no momento.'
      })
    }
  }];
}

return [{
  json: {
    response: JSON.stringify({
      profissionais: profissionais,
      total: profissionais.length,
      auto_selecionar: profissionais.length === 1
    })
  }
}];
